{
  "name": "OOP Mastery Interview Bot",
  "description": "An interactive AI-powered simulation of a technical interview focused on Object Oriented Programming concepts, class design, and architectural patterns."
}

export enum Role {
  INTERVIEWER = 'interviewer',
  CANDIDATE = 'candidate',
  SYSTEM = 'system'
}

export interface Message {
  id: string;
  role: Role;
  content: string;
  timestamp: Date;
}

export interface ChatState {
  messages: Message[];
  isThinking: boolean;
  error: string | null;
}

import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import { INTERVIEW_SYSTEM_PROMPT } from "../constants";

export class GeminiService {
  private ai: GoogleGenAI;
  private chat: Chat | null = null;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  public async startChat() {
    this.chat = this.ai.chats.create({
      model: 'gemini-3-pro-preview',
      config: {
        systemInstruction: INTERVIEW_SYSTEM_PROMPT,
        temperature: 0.7,
      },
    });

    // Start the conversation
    const response = await this.chat.sendMessage({ message: "Begin the interview by welcoming me and starting with the first OOP design scenario." });
    return response.text;
  }

  public async sendMessageStream(message: string, onChunk: (text: string) => void) {
    if (!this.chat) {
      throw new Error("Chat not initialized");
    }

    try {
      const responseStream = await this.chat.sendMessageStream({ message });
      let fullText = "";
      for await (const chunk of responseStream) {
        const c = chunk as GenerateContentResponse;
        const text = c.text || "";
        fullText += text;
        onChunk(fullText);
      }
      return fullText;
    } catch (error) {
      console.error("Gemini API Error:", error);
      throw error;
    }
  }
}

export const geminiService = new GeminiService();

import React from 'react';
import { Message, Role } from '../types';

interface ChatMessageProps {
  message: Message;
}

const ChatMessage: React.FC<ChatMessageProps> = ({ message }) => {
  const isInterviewer = message.role === Role.INTERVIEWER;

  return (
    <div className={`flex w-full mb-6 ${isInterviewer ? 'justify-start' : 'justify-end'}`}>
      <div className={`flex max-w-[85%] md:max-w-[75%] ${isInterviewer ? 'flex-row' : 'flex-row-reverse'}`}>
        <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold ${
          isInterviewer ? 'bg-indigo-600 text-white mr-3' : 'bg-slate-800 text-white ml-3'
        }`}>
          {isInterviewer ? 'AI' : 'ME'}
        </div>

        <div className={`flex flex-col ${isInterviewer ? 'items-start' : 'items-end'}`}>
          <div className={`px-4 py-3 rounded-2xl shadow-sm text-sm leading-relaxed ${
            isInterviewer 
              ? 'bg-white border border-slate-200 text-slate-800 rounded-tl-none' 
              : 'bg-indigo-600 text-white rounded-tr-none'
          }`}>
            <div className="whitespace-pre-wrap">
              {message.content.split('```').map((part, index) => {
                if (index % 2 === 1) {
                  return (
                    <div key={index} className="my-2 p-3 bg-slate-900 text-indigo-300 font-mono text-xs rounded-md overflow-x-auto border border-slate-700">
                      <code>{part.trim()}</code>
                    </div>
                  );
                }
                return <span key={index}>{part}</span>;
              })}
            </div>
          </div>
          <span className="mt-1 text-[10px] text-slate-400 font-medium">
            {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
          </span>
        </div>
      </div>
    </div>
  );
};

export default ChatMessage;

import React, { useState, useEffect, useRef } from 'react';
import { Message, Role, ChatState } from '../types';
import { geminiService } from '../services/geminiService';
import ChatMessage from './ChatMessage';
import { Send, Loader2, Sparkles, AlertCircle } from 'lucide-react';

const ChatInterface: React.FC = () => {
  const [state, setState] = useState<ChatState>({
    messages: [],
    isThinking: true,
    error: null,
  });
  const [input, setInput] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [state.messages]);

  useEffect(() => {
    const initChat = async () => {
      try {
        const welcomeText = await geminiService.startChat();
        const welcomeMsg: Message = {
          id: '1',
          role: Role.INTERVIEWER,
          content: welcomeText || "Welcome to your OOP interview. Let's start with a scenario: Animals domain. How would you design the classes?",
          timestamp: new Date(),
        };
        setState(prev => ({
          ...prev,
          messages: [welcomeMsg],
          isThinking: false,
        }));
      } catch (err) {
        setState(prev => ({
          ...prev,
          error: "Failed to connect to the interviewer. Please check your API key.",
          isThinking: false,
        }));
      }
    };

    initChat();
  }, []);

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || state.isThinking) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: Role.CANDIDATE,
      content: input,
      timestamp: new Date(),
    };

    const thinkingMessage: Message = {
      id: 'thinking',
      role: Role.INTERVIEWER,
      content: '',
      timestamp: new Date(),
    };

    setState(prev => ({
      ...prev,
      messages: [...prev.messages, userMessage, thinkingMessage],
      isThinking: true,
    }));
    setInput('');

    try {
      await geminiService.sendMessageStream(input, (fullText) => {
        setState(prev => {
          const newMessages = [...prev.messages];
          const lastMsgIndex = newMessages.length - 1;
          if (newMessages[lastMsgIndex].id === 'thinking') {
            newMessages[lastMsgIndex] = {
              ...newMessages[lastMsgIndex],
              content: fullText,
              id: Date.now().toString(),
            };
          } else {
            newMessages[lastMsgIndex].content = fullText;
          }
          return { ...prev, messages: newMessages };
        });
      });
    } catch (err) {
      setState(prev => ({
        ...prev,
        error: "Message failed to send. Try again.",
      }));
    } finally {
      setState(prev => ({ ...prev, isThinking: false }));
    }
  };

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto bg-white shadow-xl rounded-xl overflow-hidden border border-slate-200">
      {/* Header */}
      <div className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center space-x-3">
          <div className="bg-indigo-100 p-2 rounded-lg">
            <Sparkles className="w-5 h-5 text-indigo-600" />
          </div>
          <div>
            <h2 className="font-bold text-slate-800 tracking-tight">OOP Interview Simulator</h2>
            <div className="flex items-center">
              <span className="w-2 h-2 bg-green-500 rounded-full mr-2"></span>
              <span className="text-xs text-slate-500 font-medium uppercase tracking-wider">Live Interview Session</span>
            </div>
          </div>
        </div>
        <div className="hidden sm:flex space-x-2">
          <button onClick={() => window.location.reload()} className="text-xs px-3 py-1.5 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-md transition-colors font-semibold">
            Reset Interview
          </button>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-2 bg-slate-50/50">
        {state.messages.map((msg) => (
          <ChatMessage key={msg.id} message={msg} />
        ))}
        {state.isThinking && state.messages.length > 0 && state.messages[state.messages.length - 1].content === '' && (
          <div className="flex items-center space-x-2 text-slate-400 p-4">
            <Loader2 className="w-4 h-4 animate-spin" />
            <span className="text-sm font-medium">Interviewer is evaluating...</span>
          </div>
        )}
        {state.error && (
          <div className="p-4 bg-red-50 border border-red-200 rounded-lg flex items-center text-red-700 text-sm">
            <AlertCircle className="w-4 h-4 mr-2" />
            {state.error}
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="p-4 bg-white border-t border-slate-200">
        <form onSubmit={handleSend} className="relative flex items-center">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                handleSend();
              }
            }}
            placeholder="Type your design ideas or answer here..."
            className="w-full pl-4 pr-14 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all resize-none text-sm min-h-[52px] max-h-32"
            rows={1}
          />
          <button
            type="submit"
            disabled={!input.trim() || state.isThinking}
            className={`absolute right-2 p-2 rounded-lg transition-all ${
              !input.trim() || state.isThinking
                ? 'text-slate-300 cursor-not-allowed'
                : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-md'
            }`}
          >
            <Send className="w-5 h-5" />
          </button>
        </form>
        <div className="mt-2 flex justify-between items-center">
          <p className="text-[10px] text-slate-400 font-medium">
            Tip: You can ask for a <span className="text-indigo-500 font-bold italic cursor-pointer">hint</span> or the <span className="text-indigo-500 font-bold italic cursor-pointer">full solution</span> if you're stuck.
          </p>
          <p className="text-[10px] text-slate-400">Press Enter to send, Shift+Enter for new line</p>
        </div>
      </div>
    </div>
  );
};

export default ChatInterface;

