import React, { useState } from 'react';
import { Language, StudyCard } from '../types';
import { languageStudyData } from '../data/studyData';
import { ChevronRight, Code, RotateCw } from 'lucide-react';

const StudyCards: React.FC = () => {
  const [selectedLang, setSelectedLang] = useState<Language>('C#');
  const [flippedCards, setFlippedCards] = useState<Set<string>>(new Set());

  const toggleFlip = (id: string) => {
    setFlippedCards(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const languages: Language[] = ['C#', 'Java', 'Python', 'C++'];

  return (
    <div className="h-full flex flex-col space-y-6">
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
        <h2 className="text-xl font-bold text-slate-800 mb-4 flex items-center">
          <Code className="w-5 h-5 mr-2 text-indigo-600" />
          OOP Knowledge Cards
        </h2>

        <div className="flex flex-wrap gap-2">
          {languages.map(lang => (
            <button
              key={lang}
              onClick={() => {
                setSelectedLang(lang);
                setFlippedCards(new Set());
              }}
              className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${
                selectedLang === lang
                  ? 'bg-indigo-600 text-white shadow-md'
                  : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
              }`}
            >
              {lang}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 overflow-y-auto pb-10">
        {languageStudyData[selectedLang].map((card) => {
          const isFlipped = flippedCards.has(card.id);

          return (
            <div 
              key={card.id}
              onClick={() => toggleFlip(card.id)}
              className="perspective-1000 h-64 w-full cursor-pointer group"
            >
              <div className={`relative w-full h-full transition-all duration-500 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>
                {/* Front Side */}
                <div className="absolute inset-0 backface-hidden bg-white border border-slate-200 rounded-2xl shadow-sm hover:shadow-md transition-shadow flex flex-col items-center justify-center p-6">
                  <span className="text-xs font-bold text-indigo-500 uppercase tracking-widest mb-2">{selectedLang} Concept</span>
                  <h3 className="text-xl font-bold text-slate-800 text-center">{card.term}</h3>
                  <div className="mt-6 flex items-center text-slate-400 text-xs font-medium group-hover:text-indigo-500 transition-colors">
                    <RotateCw className="w-3 h-3 mr-1" />
                    Click to flip
                  </div>
                </div>

                {/* Back Side */}
                <div className="absolute inset-0 backface-hidden rotate-y-180 bg-slate-900 border border-slate-800 rounded-2xl shadow-xl flex flex-col p-6 overflow-hidden">
                  <div className="flex-1 overflow-y-auto">
                    <h4 className="text-indigo-400 font-bold text-sm mb-2">Definition</h4>
                    <p className="text-slate-300 text-sm leading-relaxed mb-4">
                      {card.definition}
                    </p>
                    <h4 className="text-indigo-400 font-bold text-sm mb-2">Example</h4>
                    <div className="bg-slate-950 p-3 rounded-lg border border-slate-800">
                      <code className="text-xs text-emerald-400 font-mono whitespace-pre-wrap">
                        {card.example}
                      </code>
                    </div>
                  </div>
                  <div className="mt-4 flex items-center justify-center text-slate-500 text-[10px] font-bold uppercase tracking-widest">
                    Back to front
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      <style>{`
        .perspective-1000 { perspective: 1000px; }
        .transform-style-3d { transform-style: preserve-3d; }
        .backface-hidden { backface-visibility: hidden; }
        .rotate-y-180 { transform: rotateY(180deg); }
      `}</style>
    </div>
  );
};

export default StudyCards;

