      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isCorrect: { type: Type.BOOLEAN },
            feedback: { type: Type.STRING, description: 'Direct feedback on the code.' },
            improvements: { type: Type.STRING, description: 'Optional suggestions for better design patterns or clean code.' },
          },
          required: ["isCorrect", "feedback"],
        },
      },
    });
    return JSON.parse(response.text);
  }
}

